    # Provide detailed failure info
    details = []
    for e in salazar_emails:
        body = e.get("body_text", "") or e.get("body", "") or ""
        full_text = (e.get("subject", "") + " " + body).lower()
        cc = e.get("cc_addr", "") or e.get("cc", "") or ""
        missing = []
