            missing.append("Salazar")
        if "cu-1026" not in full_text and "cu1026" not in full_text:
            missing.append("CU-1026")
        date_patterns = [
            "april 8", "april 08", "04/08/2026", "4/8/2026",
            "2026-04-08", "apr 8", "apr 08", "april 8, 2026",
            "april 8th", "april 8th, 2026", "04-08-2026",
