from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check jira_state.json"}
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}
    with open(jira_path) as f:
        data = json.load(f)

    def adf_to_text(node):
        """Flatten an Atlassian Document Format node (dict/list) to plain text. Passthrough for strings."""
        if node is None:
            return ""
        if isinstance(node, str):
            return node
        out = []
        def walk(n):
            if isinstance(n, dict):
                if n.get("type") == "text":
                    out.append(n.get("text", ""))
                for c in n.get("content", []) or []:
                    walk(c)
                if n.get("type") in ("paragraph", "heading", "listItem"):
                    out.append("\n")
            elif isinstance(n, list):
                for x in n:
                    walk(x)
        walk(node)
        return "".join(out).strip()

    # Navigate to issues
    issues = data.get("issues", data) if isinstance(data, dict) else data

    trent_issue = None
    matched_key = None
    if isinstance(issues, dict):
        for key, val in issues.items():
            if "trent" in key.lower() and "onboard" in key.lower():
                trent_issue = val if isinstance(val, dict) else {"raw": val}
                matched_key = key
                break
        if trent_issue is None:
            for key, val in issues.items():
                combined = (key + " " + json.dumps(val, default=str)).lower()
                if "trent" in combined and "onboard" in combined:
                    trent_issue = val if isinstance(val, dict) else {"raw": val}
                    matched_key = key
                    break
    elif isinstance(issues, list):
        for item in issues:
            if isinstance(item, dict):
                item_str = json.dumps(item, default=str).lower()
                if "trent" in item_str and "onboard" in item_str:
                    trent_issue = item
                    matched_key = item.get("key", "list_item")
                    break

    if trent_issue is None:
        all_keys = list(issues.keys()) if isinstance(issues, dict) else "N/A (list)"
        return {"pass": False, "score": 0.0, "feedback": f"Issue HR-7 not found in jira_state.json. Available keys: {all_keys}"}

    # Gather comments. Handle both schemas:
    #   (a) comments nested inside the issue: issue["comments"] = [...]
    #   (b) comments stored in a parallel top-level dict: data["comments"][issue_key] = [...]
    # Each comment's body may be a plain string OR an ADF dict.
    comments_raw = []
    nested = trent_issue.get("comments")
    if isinstance(nested, list):
        comments_raw.extend(nested)
    if isinstance(data, dict):
        parallel = data.get("comments", {})
        if isinstance(parallel, dict) and matched_key in parallel and isinstance(parallel[matched_key], list):
            comments_raw.extend(parallel[matched_key])

    comments_text_parts = []
    for c in comments_raw:
        if isinstance(c, dict):
            for field in ("body", "text", "content"):
                if field in c:
                    comments_text_parts.append(adf_to_text(c[field]))
        else:
            comments_text_parts.append(str(c))
    comments_text = " ".join(comments_text_parts)
    comments_text_lower = comments_text.lower()

    # Description. Handle both schemas:
    #   (a) issue["description"] directly (string or ADF)
    #   (b) issue["fields"]["description"] (string or ADF)
    description = trent_issue.get("description")
    if description in (None, "") and isinstance(trent_issue.get("fields"), dict):
        description = trent_issue["fields"].get("description")
    description_text = adf_to_text(description)
    desc_lower = description_text.lower()

    all_text_lower = comments_text_lower + " " + desc_lower

    required_comment_fragments = [
