    with open(slack_path) as f:
        data = json.load(f)
    channels = data.get("channels", {})
    messages = data.get("messages", {})
    expected = {
        "hr-onboarding": 15,
        "hr-offboarding": 1,
        "hr-leave-requests": 13,
        "hr-performance": 2,
        "hr-recruiting": 3,
        "hr-escalations": 0,
        "hr-general": 3
    }
    name_to_id = {}
    for cid, cdata in channels.items():
        name = cdata.get("name", "").lower().strip("#")
        name_to_id[name] = cid
    failures = []
    for channel_name, expected_count in expected.items():
        cid = name_to_id.get(channel_name)
        if cid is None:
            if expected_count == 0:
